import { useState, useEffect } from 'react';

interface UseCountdownReturn {
  hours: number;
  minutes: number;
  seconds: number;
  isExpired: boolean;
}

export const useCountdown = (initialMinutes: number): UseCountdownReturn => {
  // Initialize with a deadline based on current time + initialMinutes
  // Persist roughly by not resetting completely on refresh if we wanted to be strict,
  // but for a landing page demo, we reset on mount to ensure urgency is visible.

  const [timeLeft, setTimeLeft] = useState(initialMinutes * 60 * 1000);

  useEffect(() => {
    const interval = setInterval(() => {
      setTimeLeft((prev) => {
        if (prev <= 1000) {
          clearInterval(interval);
          return 0;
        }
        return prev - 1000;
      });
    }, 1000);

    return () => clearInterval(interval);
  }, []);

  const hours = Math.floor((timeLeft / (1000 * 60 * 60)) % 24);
  const minutes = Math.floor((timeLeft / 1000 / 60) % 60);
  const seconds = Math.floor((timeLeft / 1000) % 60);

  return { hours, minutes, seconds, isExpired: timeLeft <= 0 };
};

import { useState, useEffect } from 'react';

export const useScrollProgress = (): number => {
  const [scrollProgress, setScrollProgress] = useState(0);

  useEffect(() => {
    const updateScroll = () => {
      const currentScroll = window.scrollY;
      const scrollHeight = document.documentElement.scrollHeight - window.innerHeight;

      if (scrollHeight) {
        setScrollProgress((currentScroll / scrollHeight) * 100);
      }
    };

    window.addEventListener('scroll', updateScroll);
    return () => window.removeEventListener('scroll', updateScroll);
  }, []);

  return scrollProgress;
};

import { useState, useEffect } from 'react';

interface UseCookieConsentReturn {
  hasConsented: boolean;
  acceptCookies: () => void;
}

export const useCookieConsent = (): UseCookieConsentReturn => {
  const [hasConsented, setHasConsented] = useState(true); // Default true to avoid flash, then check effect

  useEffect(() => {
    const consent = localStorage.getItem('gusta_cookie_consent');
    if (!consent) {
      setHasConsented(false);
    }
  }, []);

  const acceptCookies = () => {
    localStorage.setItem('gusta_cookie_consent', 'true');
    setHasConsented(true);
  };

  return { hasConsented, acceptCookies };
};

import React from 'react';
import { motion } from 'framer-motion';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'accent' | 'white';
  size?: 'sm' | 'md' | 'lg' | 'xl';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'accent', 
  size = 'md', 
  fullWidth = false,
  className = '',
  ...props 
}) => {
  const baseStyles = "font-heading font-bold rounded-full transition-all duration-300 shadow-lg hover:shadow-xl active:scale-95 flex items-center justify-center gap-2";

  const variants = {
    primary: "bg-primary text-white hover:bg-primary/90",
    secondary: "bg-secondary text-white hover:bg-secondary/90",
    accent: "bg-accent text-white hover:bg-accent/90 animate-pulse-slow",
    white: "bg-white text-primary hover:bg-gray-100",
  };

  const sizes = {
    sm: "px-4 py-2 text-sm",
    md: "px-6 py-3 text-base",
    lg: "px-8 py-4 text-lg",
    xl: "px-10 py-5 text-xl uppercase tracking-wide",
  };

  return (
    <motion.button
      whileHover={{ scale: 1.05 }}
      whileTap={{ scale: 0.95 }}
      className={`
        ${baseStyles} 
        ${variants[variant]} 
        ${sizes[size]} 
        ${fullWidth ? 'w-full' : ''} 
        ${className}
      `}
      {...props}
    >
      {children}
    </motion.button>
  );
};

